import test from "node:test";
import assert from "node:assert/strict";

import { buildPolicy } from "../src/policy-config.mjs";
import { ReportService } from "../src/report-service.mjs";

const defaults = {
  allowedRegions: ["us-west", "us-east"],
  requiredScopes: ["tenant:verified"]
};

test("a present empty regional overlay remains deny-all", () => {
  const policy = buildPolicy(defaults, { allowedRegions: [] });
  assert.deepEqual(policy.allowedRegions, []);
  assert.deepEqual(policy.requiredScopes, ["tenant:verified"]);
});

test("deny-all regional configuration rejects an otherwise complete principal", () => {
  const service = new ReportService({ defaults, overlay: { allowedRegions: [] } });
  const response = service.readSummary({
    tenant: "frozen-tenant",
    region: "us-west",
    scopes: ["tenant:verified", "report:admin"]
  });
  assert.equal(response.status, 403);
  assert.equal(response.code, "region_not_allowed");
});
